figure.artwork:
@entry { ... }                       ; anonymous, typeless
@entry name { ... }                  ; labeled, typeless
@entry name some.pkg.Type { ... }    ; labeled and typed
@entry some.pkg.Type { ... }         ; typed only (no label)

@proto { <message-body> }                  ; anonymous
@proto <dotted-name> { <message-body> }    ; named
@proto """<proto-source>"""                ; source-form file
@proto b"<base64-FileDescriptorSet>"       ; descriptor form

headers = {
  "X-Request-ID":  "abc123"
  "Content-Type":  "application/pxf"
}

message Node {
  string id = 1;
  repeated Node children = 5 [(pxf.key) = "id"];
}

children {
  greeting    { type = "Label" }
  counter_row { type = "HBox"  }
}

regions {
  "us-east-1" { replicas = 3 }
  "eu-west-2" { replicas = 1 }
}

extend google.protobuf.FieldOptions {
  bool   required = 50000;
  string default  = 50001;
  string key      = 50002;
}

extend google.protobuf.FileOptions {
  uint32 schema_id = 50100;
  uint32 version   = 50101;
}

extend google.protobuf.MessageOptions {
  uint32 template_id = 50200;
}

extend google.protobuf.FieldOptions {
  uint32 length   = 50300;
  string encoding = 50301;
}

message Envelope {
  int32  status          = 1;
  string transport_error = 2;
  bytes  data            = 3;
  AppError error         = 4;
}

message AppError {
  string code               = 1;
  string message            = 2;
  repeated string args      = 3;
  repeated FieldError details = 4;
  map<string,string> metadata = 5;
}

message FieldError {
  string field   = 1;
  string code    = 2;
  string message = 3;
  repeated string args = 4;
}

list.t:
Sensitivity-class taxonomy. An additive class: parameter on
@sensitive () distinguishing e.g. secret / PII /
confidential.
